<?php try{$promos=db()->query('SELECT * FROM product_promotions ORDER BY id DESC')->fetchAll();}catch(Throwable $e){$promos=[];} ?>
<div class="ao-hero-slim"><h2>Promosyonlar</h2><p>Kuponlar, indirimler, ürün bazlı kampanyalar ve süre sınırları.</p></div>
<div class="ao-grid two"><div class="ao-card"><h3>Yeni Kupon / Kampanya</h3><form method="post" action="<?= url('admin/product-center/promotion-save') ?>" class="ao-form ao-form-grid"><?= csrf_field() ?><label>Kupon Kodu<input name="code" required placeholder="YENI10"></label><label>Başlık<input name="title" placeholder="Yeni müşteri indirimi"></label><label>İndirim Türü<select name="discount_type"><option value="percent">Yüzde</option><option value="amount">Tutar</option></select></label><label>İndirim Değeri<input name="discount_value" value="10"></label><label>Minimum Sepet<input name="min_total" value="0"></label><label>Kullanım Limiti<input name="usage_limit" value="0"></label><label>Başlangıç<input type="date" name="starts_at"></label><label>Bitiş<input type="date" name="ends_at"></label><label><input type="checkbox" name="is_active" value="1" checked> Aktif</label><div><button class="ao-btn">Kaydet</button></div></form></div><div class="ao-card"><h3>Kayıtlı Promosyonlar</h3><?php foreach($promos as $p): ?><div class="ao-list-card"><div class="ao-list-title"><span class="letter">%</span><div><h3><?= e($p['code']) ?></h3><small><?= e($p['title']) ?></small></div></div><span class="ao-pill"><?= e($p['discount_type']) ?></span><span><?= e($p['discount_value']) ?></span><span class="ao-pill <?= !empty($p['is_active'])?'green':'red' ?>"><?= !empty($p['is_active'])?'Aktif':'Pasif' ?></span><div class="ao-action-row"><a class="ao-btn small" href="<?= url('admin/product-center/promotion-toggle?id='.(int)$p['id'].'&csrf_token='.csrf_token()) ?>">Aktif/Pasif</a><a data-confirm="Promosyon silinsin mi?" class="ao-btn small ao-mini-danger" href="<?= url('admin/product-center/promotion-delete?id='.(int)$p['id'].'&csrf_token='.csrf_token()) ?>">Sil</a></div></div><?php endforeach; if(!$promos): ?><p class="ao-muted">Henüz promosyon yok.</p><?php endif; ?></div></div>
